const event = $input.first().json || {};
const sec = event.security_analysis || {};
const risk = event.risk_analysis || {};
const correlationId = event.correlation_id || `CID-SEC-LOCKDOWN-${(event.thing_id || 'thing').replace(/[^a-zA-Z0-9]/g, '-')}-${Date.now()}`;
const issuedAt = sec.analyzed_at || new Date().toISOString();
return [{
  json: {
    thing_id: event.thing_id,
    correlation_id: correlationId,
    system_mode: event.system_mode || 'NORMAL',
    payload: event.payload || {},
    security_analysis: sec,
    risk_analysis: risk,
    agent_source: '04_security_maintenance_agents',
    triggered_action: {
      agent: 'control',
      command: 'LOCKDOWN',
      priority: 'CRITICAL',
      source_agent: '04_security_maintenance_agents',
      correlation_id: correlationId,
      risk_score: Number(risk.risk_score || 0),
      reason: Array.isArray(sec.combined_events) ? sec.combined_events : [],
      issued_at: issuedAt
    }
  }
}];

const rawEvent = $input.first().json || {};
const event = (rawEvent.body && typeof rawEvent.body === 'object' && rawEvent.body.thing_id) ? rawEvent.body : rawEvent;
const payload = event.payload || {};
const security = payload.security || {};
const door = payload.door || {};
const cabin = payload.cabin || {};
const thingId = event.thing_id || $env.PRIMARY_THING_ID || 'building:floor1:elevator';
const now = Date.now();
const nowIso = new Date(now).toISOString();
const windowMs = Number($env.RFID_FAILURE_WINDOW_MINUTES || 5) * 60 * 1000;
const threshold = Number($env.RFID_BLACKLIST_THRESHOLD || 3);

const state = $getWorkflowStaticData('global');
const key = `security:${thingId}`;
state[key] = state[key] || {
  rfid_failures: {},
  blacklisted_cards: [],
  active_incidents: []
};

const memory = state[key];
const card = security.rfid_last_card || '';

if (card && security.rfid_access_granted === false) {
  const attempts = memory.rfid_failures[card] || [];
  attempts.push(now);
  memory.rfid_failures[card] = attempts.filter((ts) => now - ts <= windowMs);
}

for (const knownCard of Object.keys(memory.rfid_failures)) {
  memory.rfid_failures[knownCard] = memory.rfid_failures[knownCard].filter((ts) => now - ts <= windowMs);
  if (memory.rfid_failures[knownCard].length === 0) delete memory.rfid_failures[knownCard];
}

const repeatedCards = Object.keys(memory.rfid_failures)
  .filter((knownCard) => memory.rfid_failures[knownCard].length >= threshold);

memory.blacklisted_cards = Array.from(new Set([...(memory.blacklisted_cards || []), ...repeatedCards]));

const combined = [];
if (door.forced_entry && security.audio_distress) combined.push('FORCED_DOOR_AUDIO_DISTRESS');
if (door.forced_entry && String(cabin.direction || 'IDLE') !== 'IDLE') combined.push('FORCED_DOOR_WHILE_MOVING');
if (door.forced_entry && security.rfid_access_granted === false) combined.push('RFID_DENIED_FORCED_DOOR');
if (repeatedCards.length > 0) combined.push('REPEATED_ACCESS_ATTEMPTS');

let securityState = 'NORMAL';
let alertLevel = 'NORMAL';
let severity = 'INFO';
const actions = [];
const recommendation = [];

if (combined.some((item) => ['FORCED_DOOR_AUDIO_DISTRESS', 'FORCED_DOOR_WHILE_MOVING'].includes(item))) {
  securityState = 'LOCKDOWN';
  alertLevel = 'CRITICAL';
  severity = 'CRITICAL';
  actions.push({ agent: 'control', command: 'LOCKDOWN', priority: 'CRITICAL', reason: combined });
  recommendation.push('Immediate operator review and physical security inspection required.');
} else if (door.forced_entry || security.audio_distress) {
  securityState = 'HUMAN_REVIEW_REQUIRED';
  alertLevel = 'CRITICAL';
  severity = 'CRITICAL';
  actions.push({ agent: 'control', command: 'LOCKDOWN', priority: 'CRITICAL', reason: [door.forced_entry ? 'FORCED_ENTRY' : 'DISTRESS_AUDIO'] });
  recommendation.push('Lockdown recommended until the incident is acknowledged.');
} else if (combined.length > 0) {
  securityState = 'SUSPICIOUS';
  alertLevel = 'WARNING';
  severity = 'WARNING';
  recommendation.push('Monitor access attempts and verify RFID credential ownership.');
} else if (card && security.rfid_access_granted === false) {
  securityState = 'WATCH';
  alertLevel = 'WATCH';
  recommendation.push('Single denied RFID attempt observed.');
}

const activeSecurityIncident = ['LOCKDOWN', 'HUMAN_REVIEW_REQUIRED', 'SUSPICIOUS'].includes(securityState);
if (activeSecurityIncident) {
  memory.active_incidents.push({
    correlation_id: event.correlation_id,
    state: securityState,
    combined,
    observed_at: nowIso
  });
  memory.active_incidents = memory.active_incidents.slice(-50);
}

state[key] = memory;

return [{
  json: {
    ...event,
    severity: severity === 'CRITICAL' ? 'CRITICAL' : event.severity || severity,
    security_analysis: {
      state: securityState,
      alert_level: alertLevel,
      severity,
      blacklisted_cards: memory.blacklisted_cards,
      repeated_cards: repeatedCards,
      combined_events: combined,
      active_security_incident: activeSecurityIncident,
      human_review_required: securityState === 'HUMAN_REVIEW_REQUIRED',
      security_recommendation: recommendation.join(' '),
      actions,
      analyzed_at: nowIso
    },
    metadata: {
      ...(event.metadata || {}),
      workflow: '04_security_maintenance_agents',
      node: 'Security State Machine',
      schema_version: '1.0'
    }
  }
}];

const body = $input.first().json || {};
const features = body.features || {};
return [{ json: { thing_id: body.thingId || 'building:floor1:elevator', payload: { cabin: features.cabin?.properties || {}, door: features.door?.properties || {}, motor: { vibration_g: features.motor?.properties?.vibration_g ?? features.motor?.properties?.vibration_level ?? 0, vibration_baseline_g: features.motor?.properties?.vibration_baseline_g ?? 0.05, temperature_c: features.motor?.properties?.temperature_c ?? 0, hours_operated: features.motor?.properties?.hours_operated ?? 0, current_draw_a: features.motor?.properties?.current_draw_a ?? 0, power_kw: features.motor?.properties?.power_kw ?? 0, health_status: features.motor?.properties?.health_status ?? 'UNKNOWN' }, security: features.security?.properties || {} }, risk_analysis: { flags: [], severity: 'INFO', risk_score: body.attributes?.risk_score || 0 }, source: 'scheduled-maintenance-scan' } }];

const rawInput = $input.first().json || {};
const input = (rawInput.body && typeof rawInput.body === 'object' && rawInput.body.thing_id) ? rawInput.body : rawInput;
const payload = input.payload || {};
const motor = payload.motor || {};
const door = payload.door || {};
const cabin = payload.cabin || {};
const energy = payload.energy || {};
const flags = input.risk_analysis?.flags || [];

const num = (value, fallback = 0) => {
  const n = Number(value);
  return Number.isFinite(n) ? n : fallback;
};

const clamp = (value, min, max) => Math.max(min, Math.min(max, value));
const thingId = input.thing_id || $env.PRIMARY_THING_ID || 'building:floor1:elevator';
const now = new Date();
const vibRatio = num(motor.vibration_g) / Math.max(num(motor.vibration_baseline_g, 0.05), 0.001);
const hoursFactor = clamp(num(motor.hours_operated) / 10000, 0, 1);
const loadFactor = clamp(num(cabin.load_kg) / Math.max(num(cabin.max_load_kg, 800), 1), 0, 1.5);
const tempFactor = clamp((num(motor.temperature_c) - 55) / 45, 0, 1);
const currentFactor = clamp(num(motor.current_draw_a) / 45, 0, 1);
const powerFactor = clamp(num(motor.power_kw) / 12, 0, 1);
const doorFactor = clamp(num(door.cycle_count) / 30000, 0, 1);
const forcedStopFactor = flags.filter((flag) => ['EMERGENCY_STOP_ACTIVE', 'STUCK_BETWEEN_FLOORS'].includes(flag)).length > 0 ? 1 : 0;
const energyFactor = Array.isArray(energy.recommendations) && energy.recommendations.length > 0 ? 1 : 0;

const wearIndex = clamp(
  (hoursFactor * 22) +
  (loadFactor * 10) +
  (clamp(vibRatio / 4, 0, 1) * 28) +
  (tempFactor * 14) +
  (currentFactor * 10) +
  (powerFactor * 7) +
  (doorFactor * 6) +
  (forcedStopFactor * 8) +
  (energyFactor * 5),
  0,
  100
);

let priority = 'LOW';
let estimatedFailureDays = 120;
const tasks = [];
const issueReasons = [];

if (wearIndex >= 85 || vibRatio >= 4 || num(motor.temperature_c) >= 90) {
  priority = 'CRITICAL';
  estimatedFailureDays = 3;
  tasks.push({ task: 'Immediate motor, brake, and bearing inspection', urgency: 'IMMEDIATE', estimated_hours: 6 });
  issueReasons.push('critical_wear');
} else if (wearIndex >= 70 || vibRatio >= 3 || num(motor.temperature_c) >= 80) {
  priority = 'HIGH';
  estimatedFailureDays = 10;
  tasks.push({ task: 'Motor thermal inspection', urgency: 'HIGH', estimated_hours: 3 });
  tasks.push({ task: 'Vibration and bearing diagnostics', urgency: 'HIGH', estimated_hours: 3 });
  issueReasons.push('high_wear');
} else if (wearIndex >= 50 || vibRatio >= 2.2 || flags.includes('HIGH_CURRENT_DRAW')) {
  priority = 'MEDIUM';
  estimatedFailureDays = 30;
  tasks.push({ task: 'Planned vibration trend review', urgency: 'PLANNED', estimated_hours: 2 });
  tasks.push({ task: 'Current draw and power baseline check', urgency: 'PLANNED', estimated_hours: 2 });
  issueReasons.push('degradation_trend');
} else {
  tasks.push({ task: 'Routine inspection', urgency: 'ROUTINE', estimated_hours: 1 });
  issueReasons.push('routine');
}

const issueKey = issueReasons.join('+');
const workOrderId = `WO-${thingId.replace(/[^a-zA-Z0-9]/g, '-')}-${issueKey}-${now.getTime()}`;
const nextServiceDate = new Date(now);
nextServiceDate.setDate(nextServiceDate.getDate() + clamp(estimatedFailureDays - 2, 1, 45));

return [{
  json: {
    ...input,
    work_order: {
      work_order_id: workOrderId,
      correlation_id: input.correlation_id,
      thing_id: thingId,
      issue_key: issueKey,
      priority,
      wear_index: Math.round(wearIndex * 100) / 100,
      estimated_failure_days: estimatedFailureDays,
      tasks,
      evidence: {
        vibration_ratio: Math.round(vibRatio * 100) / 100,
        motor_temperature_c: num(motor.temperature_c),
        hours_operated: num(motor.hours_operated),
        current_draw_a: num(motor.current_draw_a),
        power_kw: num(motor.power_kw),
        door_cycle_count: num(door.cycle_count),
        flags,
        energy_recommendations: energy.recommendations || []
      },
      status: 'OPEN',
      notify_required: ['MEDIUM', 'HIGH', 'CRITICAL'].includes(priority),
      next_service_date: nextServiceDate.toISOString().slice(0, 10),
      generated_at: now.toISOString()
    }
  }
}];
